('economics:2-3-supply:fib:07ff77da', 'economics', 'economics:2-3-supply', '2.3 Supply', 'fib', 'fib', 2, '{"question": "Higher taxes raise firms'' costs and shift the supply curve to the ___B1___. Subsidies lower costs and shift it to the ___B2___.", "blankOptions": {"B1": ["left", "supplied", "origin", "rises"], "B2": ["supplied", "demand", "unitary", "right"]}}'::jsonb, '{"blanks": {"B1": "left", "B2": "right"}}'::jsonb),
('economics:2-3-supply:fib:2d1beefe', 'economics', 'economics:2-3-supply', '2.3 Supply', 'fib', 'fib', 2, '{"question": "PES = percentage change in quantity ___B1___ ÷ percentage change in ___B2___. The answer is always positive.", "blankOptions": {"B1": ["supplied", "elastic", "origin", "rises"], "B2": ["elastic", "unitary", "price", "inelastic"]}}'::jsonb, '{"blanks": {"B1": "supplied", "B2": "price"}}'::jsonb),
('economics:2-3-supply:fib:4ea15196', 'economics', 'economics:2-3-supply', '2.3 Supply', 'fib', 'fib', 2, '{"question": "Any straight-line supply curve that passes through the ___B1___ has ___B2___ price elasticity of supply, whatever its slope.", "blankOptions": {"B1": ["inelastic", "left", "expansion", "origin"], "B2": ["left", "elastic", "supplied", "unitary"]}}'::jsonb, '{"blanks": {"B1": "origin", "B2": "unitary"}}'::jsonb),
