('economics:2-3-supply:match:c04e8cdf', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Supply”?", "options": ["The amount one single firm is willing to supply at each price", "All the individual supply curves in a market added together", "The amount producers are willing and able to sell at a given price in a given time period", "As price rises, quantity supplied rises — a direct relationship"]}'::jsonb, '{"answer": 2, "explain": "“Supply” means: The amount producers are willing and able to sell at a given price in a given time period"}'::jsonb),
('economics:2-3-supply:match:98d5f4b1', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Individual supply”?", "options": ["All the individual supply curves in a market added together", "As price rises, quantity supplied rises — a direct relationship", "A rise in quantity supplied caused by a rise in the good''s own price", "The amount one single firm is willing to supply at each price"]}'::jsonb, '{"answer": 3, "explain": "“Individual supply” means: The amount one single firm is willing to supply at each price"}'::jsonb),
('economics:2-3-supply:match:5b937a62', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market supply”?", "options": ["As price rises, quantity supplied rises — a direct relationship", "A rise in quantity supplied caused by a rise in the good''s own price", "All the individual supply curves in a market added together", "A fall in quantity supplied caused by a fall in the good''s own price"]}'::jsonb, '{"answer": 2, "explain": "“Market supply” means: All the individual supply curves in a market added together"}'::jsonb),
('economics:2-3-supply:match:8cc63bc6', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “The law of supply”?", "options": ["As price rises, quantity supplied rises — a direct relationship", "A rise in quantity supplied caused by a rise in the good''s own price", "A fall in quantity supplied caused by a fall in the good''s own price", "Caused by a non-price factor: costs, taxes, subsidies, technology, weather, number or size of producers, regulation"]}'::jsonb, '{"answer": 0, "explain": "“The law of supply” means: As price rises, quantity supplied rises — a direct relationship"}'::jsonb),
('economics:2-3-supply:match:4f939cc6', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Expansion of supply”?", "options": ["A rise in quantity supplied caused by a rise in the good''s own price", "A fall in quantity supplied caused by a fall in the good''s own price", "Caused by a non-price factor: costs, taxes, subsidies, technology, weather, number or size of producers, regulation", "A government payment that lowers a firm''s costs and shifts supply to the right"]}'::jsonb, '{"answer": 0, "explain": "“Expansion of supply” means: A rise in quantity supplied caused by a rise in the good''s own price"}'::jsonb),
('economics:2-3-supply:match:ef5aed6d', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Contraction of supply”?", "options": ["Caused by a non-price factor: costs, taxes, subsidies, technology, weather, number or size of producers, regulation", "A government payment that lowers a firm''s costs and shifts supply to the right", "Percentage change in quantity supplied divided by percentage change in price", "A fall in quantity supplied caused by a fall in the good''s own price"]}'::jsonb, '{"answer": 3, "explain": "“Contraction of supply” means: A fall in quantity supplied caused by a fall in the good''s own price"}'::jsonb),
('economics:2-3-supply:match:879b38ef', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Shift of the supply curve”?", "options": ["A government payment that lowers a firm''s costs and shifts supply to the right", "Percentage change in quantity supplied divided by percentage change in price", "Quantity supplied changes by a bigger percentage than price — drawn as a very flat curve", "Caused by a non-price factor: costs, taxes, subsidies, technology, weather, number or size of producers, regulation"]}'::jsonb, '{"answer": 3, "explain": "“Shift of the supply curve” means: Caused by a non-price factor: costs, taxes, subsidies, technology, weather, number or size of producers, regulation"}'::jsonb),
('economics:2-3-supply:match:5f6a2b75', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Subsidy”?", "options": ["A government payment that lowers a firm''s costs and shifts supply to the right", "Percentage change in quantity supplied divided by percentage change in price", "Quantity supplied changes by a bigger percentage than price — drawn as a very flat curve", "Quantity supplied changes by a smaller percentage than price — drawn as a very steep curve"]}'::jsonb, '{"answer": 0, "explain": "“Subsidy” means: A government payment that lowers a firm''s costs and shifts supply to the right"}'::jsonb),
('economics:2-3-supply:match:49e15544', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price elasticity of supply (PES)”?", "options": ["Quantity supplied changes by a bigger percentage than price — drawn as a very flat curve", "Quantity supplied changes by a smaller percentage than price — drawn as a very steep curve", "Percentage change in quantity supplied divided by percentage change in price", "A vertical supply curve — the same quantity is supplied whatever the price, like fixed stadium seats"]}'::jsonb, '{"answer": 2, "explain": "“Price elasticity of supply (PES)” means: Percentage change in quantity supplied divided by percentage change in price"}'::jsonb),
('economics:2-3-supply:match:6fdcb93b', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price elastic supply”?", "options": ["Quantity supplied changes by a smaller percentage than price — drawn as a very steep curve", "A vertical supply curve — the same quantity is supplied whatever the price, like fixed stadium seats", "Quantity supplied changes by a bigger percentage than price — drawn as a very flat curve", "Deliberately running below maximum output (often 75–85%) so production can be increased quickly"]}'::jsonb, '{"answer": 2, "explain": "“Price elastic supply” means: Quantity supplied changes by a bigger percentage than price — drawn as a very flat curve"}'::jsonb),
('economics:2-3-supply:match:fa43610c', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Price inelastic supply”?", "options": ["A vertical supply curve — the same quantity is supplied whatever the price, like fixed stadium seats", "Quantity supplied changes by a smaller percentage than price — drawn as a very steep curve", "Deliberately running below maximum output (often 75–85%) so production can be increased quickly", "The amount producers are willing and able to sell at a given price in a given time period"]}'::jsonb, '{"answer": 1, "explain": "“Price inelastic supply” means: Quantity supplied changes by a smaller percentage than price — drawn as a very steep curve"}'::jsonb),
('economics:2-3-supply:match:7ac7bf0b', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Perfectly inelastic supply”?", "options": ["A vertical supply curve — the same quantity is supplied whatever the price, like fixed stadium seats", "Deliberately running below maximum output (often 75–85%) so production can be increased quickly", "The amount producers are willing and able to sell at a given price in a given time period", "The amount one single firm is willing to supply at each price"]}'::jsonb, '{"answer": 0, "explain": "“Perfectly inelastic supply” means: A vertical supply curve — the same quantity is supplied whatever the price, like fixed stadium seats"}'::jsonb),
('economics:2-3-supply:match:ff35f151', 'economics', 'economics:2-3-supply', '2.3 Supply', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Spare capacity”?", "options": ["The amount producers are willing and able to sell at a given price in a given time period", "The amount one single firm is willing to supply at each price", "Deliberately running below maximum output (often 75–85%) so production can be increased quickly", "All the individual supply curves in a market added together"]}'::jsonb, '{"answer": 2, "explain": "“Spare capacity” means: Deliberately running below maximum output (often 75–85%) so production can be increased quickly"}'::jsonb),
('economics:2-4-price:exam:00105b3a', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q1", "question": "When producers charge P0, this means...", "options": ["at Q0 more is demanded than is supplied", "if demand were to rise, firms would make less profit", "consumers will demand the equilibrium quantity Q0", "the market is in equilibrium whatever the price"], "caseStudy": "<img src=\"/images/economics/2-4-equilibrium-p0-q0-extracted.png\" alt=\"Diagram from the OCR exam paper: supply and demand curves crossing at price P0 and quantity Q0, marked with dashed lines\" style=\"display:block;width:100%;max-width:440px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "P0 is where the curves cross — the equilibrium price. What quantity do consumers demand AT that price?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1b)</h5>\n<p><strong>Answer: C — consumers will demand the equilibrium quantity Q0</strong></p>\n<ul>\n<li>At the equilibrium price P0, quantity demanded equals quantity supplied at exactly Q0 — the market clears.</li>\n<li>A describes excess demand (wrong at equilibrium); D is wrong because equilibrium holds at ONE price, not any price.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:78df28fe', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Bad weather conditions are most likely to result in...", "options": ["an increase in the price of wheat", "an increase in wheat production", "greater demand for wheat", "higher wages for agricultural workers"], "hint": "Bad weather hits the SUPPLY side: less wheat harvested → supply shifts left → what happens to the price?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — an increase in the price of wheat</strong></p>\n<ul>\n<li>Bad weather cuts the harvest — supply shifts left, so the equilibrium price rises and quantity falls.</li>\n<li>B is the opposite of what happens; weather doesn''t change consumers'' demand (C).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:5c205ab0', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q3", "question": "The diagram shows the supply and demand curves for a product. An increase in demand means that...", "options": ["producers will reduce prices and equilibrium price falls", "producers will produce more and equilibrium output is increased", "producers will not supply more than the equilibrium output", "producers will not change prices and equilibrium price is unchanged"], "caseStudy": "<img src=\"/images/economics/2-4-vertical-supply-extracted.png\" alt=\"Diagram from the OCR exam paper: a vertical supply curve S crossed by a downward-sloping demand curve D\" style=\"display:block;width:100%;max-width:420px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "The supply curve is VERTICAL — perfectly price inelastic. If demand shifts right, can output rise at all?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1b)</h5>\n<p><strong>Answer: C — producers will not supply more than the equilibrium output</strong></p>\n<ul>\n<li>The vertical supply curve is perfectly price inelastic: quantity supplied is fixed. A demand increase raises the price but output cannot rise.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:e08273db', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q4", "question": "A competitive market is in equilibrium. Which one of the following statements is true?", "options": ["Consumers are unwilling to buy all the units produced", "Producers are leaving the industry", "Quantity demanded equals quantity supplied", "Quantity supplied exceeds quantity demanded"], "hint": "The definition of equilibrium — the market CLEARS. Which statement says exactly that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1b)</h5>\n<p><strong>Answer: C — Quantity demanded equals quantity supplied</strong></p>\n<ul>\n<li>Equilibrium means the market clears: Qd = Qs. A and D describe excess supply — a disequilibrium.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:11ba2b1f', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q7", "question": "If the price is currently P1 what would be the most likely result?", "options": ["Equilibrium price will rise", "More buyers will enter the market", "The market will be in equilibrium", "There will be excess supply"], "caseStudy": "<img src=\"/images/economics/2-4-apples-p1-extracted.png\" alt=\"Diagram from the OCR exam paper: supply and demand for apples with a price P1 marked by a dashed line above the point where the curves cross\" style=\"display:block;width:100%;max-width:440px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "P1 sits ABOVE the crossing point. At a price above equilibrium, which is bigger — quantity supplied or quantity demanded?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: D — There will be excess supply</strong></p>\n<ul>\n<li>Above the equilibrium price, quantity supplied exceeds quantity demanded — a surplus that will push the price back down.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most of the candidates gave D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:928fbe7d', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q8", "question": "This is an example of price acting as both...", "options": ["a reflection of worth and a transmission of preferences", "a signaller and a transmission of preferences", "resource rationing and a signaller", "resource rationing and an opportunity cost indicator"], "caseStudy": "<p>In a market where demand and prices are falling this means that fewer resources are needed.</p>", "hint": "Falling demand TELLS producers what consumers no longer want (transmission of preferences), and the falling price SHOWS where resources are no longer needed (signalling).", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — a signaller and a transmission of preferences</strong></p>\n<ul>\n<li>The falling price signals that fewer resources are needed in this market, and consumers'' reduced buying transmits their preferences to producers.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Although nearly half of the candidates gave the correct answer B, there was substantial support for A and C showing some confusion over the role of price.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:75653c82', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q9", "question": "Shops usually hold a ''cut price'' sale of goods because the original price was...", "options": ["above the equilibrium price", "at the equilibrium price", "below the equilibrium price", "causing excess demand"], "hint": "A sale exists to clear UNSOLD stock. Unsold stock means the price was set where quantity supplied exceeded quantity demanded — which side of equilibrium is that?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — above the equilibrium price</strong></p>\n<ul>\n<li>A price above equilibrium creates excess supply — unsold stock. The sale cuts the price towards equilibrium to clear it.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:0e010249', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q10", "question": "This increased production of organic vegetables is a result of which role of price?", "options": ["Rationing", "Signalling", "Specialisation", "Substitution"], "caseStudy": "<p>Farmers have started to produce more organic vegetables. They have found that many people are willing to pay a high price for organic vegetables.</p>", "hint": "The high price is a message to farmers: ''resources are needed HERE''. Which role of price sends that message?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Signalling</strong></p>\n<ul>\n<li>The high price signals to producers that consumers value organic vegetables, pulling more resources into producing them.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:31c62345', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q11", "question": "The diagram shows the market for houses in Plumgarth in 2023. If the price of houses decreases from p to p1 which of these statements is correct?", "options": ["Buyers will find it easier to purchase a house", "Buyers will find it more difficult to save money to purchase a house", "Sellers will be less willing to put their house on the market", "Sellers will not be able to sell their house"], "caseStudy": "<img src=\"/images/economics/2-4-plumgarth-houses-extracted.png\" alt=\"Diagram from the OCR exam paper: the market for houses in Plumgarth with supply and demand curves and two prices marked, p at the equilibrium and p1 below it\" style=\"display:block;width:100%;max-width:420px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "Think about SELLERS at a lower price — the law of supply. Would they be more or less willing to sell? (And careful: cheaper houses don''t automatically mean buyers can all purchase — there are fewer on the market.)", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Sellers will be less willing to put their house on the market</strong></p>\n<ul>\n<li>At a lower price, quantity supplied contracts — the law of supply. Sellers hold back rather than sell cheaply.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response to this question was Option C. Incorrect responses frequently gave Option A or, to a lesser extent, Option D and indicated a lack of knowledge and understanding of the implications of falling prices in a local housing market.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:e12d371b', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q12", "question": "This shows...", "options": ["an efficient working of the market as consumers respond to price signals", "equilibrium price and quantity will not be restored after a price change", "opportunity cost as the supplier increases price to the consumer", "the transmission of preferences from consumers to producers"], "caseStudy": "<p>If the price of olive oil increases consumers are likely to demand less.</p>", "hint": "Consumers reacting to a price change is the market working exactly as it should — responding to price signals.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — an efficient working of the market as consumers respond to price signals</strong></p>\n<ul>\n<li>Consumers cutting back when price rises is the price mechanism efficiently rationing the good — the market working as intended.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option A as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:88c71e50', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q16", "question": "What is most likely to cause a decrease in the price of carrots?", "options": ["A decrease in the demand for substitutes of carrots", "An increase in the demand for complements of carrots", "An increase in the number of farm workers", "An increase in the popularity of carrots"], "hint": "A price FALL needs either less demand or MORE supply. Three options raise demand for carrots — one increases what farms can produce.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — An increase in the number of farm workers</strong></p>\n<ul>\n<li>More farm workers means more carrots can be grown — supply shifts right and the price falls.</li>\n<li>B and D increase the demand for carrots (price rises); A pushes buyers of substitutes towards... their now less-demanded substitutes — not a fall in carrot prices.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response was Option C. Incorrect responses ranged across the other three options and indicated a misunderstanding of the factors affecting the demand for products and the resulting effect on their prices.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:bc13609f', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q17", "question": "The price of a good is most likely to fall when...", "options": ["demand and supply both decrease", "demand and supply both increase", "demand decreases and supply increases", "demand increases and supply decreases"], "hint": "For the price to DEFINITELY fall, both forces must push it the same way: less demand pushes price down AND more supply pushes price down.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — demand decreases and supply increases</strong></p>\n<ul>\n<li>Both shifts push the price DOWN — the only combination where the price fall is certain. In A, B and D the two forces pull the price in opposite directions.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>Most candidates gave Option C as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:bf7b47f8', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q20", "question": "The diagram shows the market supply and demand curves for a good. If there is a decrease in supply, how will this affect the equilibrium price and quantity?", "options": ["The price will decrease and quantity will increase", "The price will increase and quantity will decrease", "The quantity will increase but price will not change", "There will be no change because the market is in equilibrium"], "caseStudy": "<img src=\"/images/economics/2-4-q20-supply-demand-extracted.png\" alt=\"Diagram from the OCR exam paper showing a market with curves labelled Supply and Demand crossing at price p1 and quantity q1\" style=\"display:block;width:100%;max-width:440px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "Whatever the diagram looks like, the chain is fixed: supply DECREASES (shifts left) → price UP, quantity DOWN.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — The price will increase and quantity will decrease</strong></p>\n<ul>\n<li>A decrease in supply shifts the supply curve left: less is available at every price, so the equilibrium price rises and the equilibrium quantity falls.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:d2a30e16', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q22", "question": "A market starts in equilibrium and then demand falls. Which of the following is most likely to happen?", "options": ["A higher equilibrium price and equilibrium quantity", "A higher equilibrium price and lower equilibrium quantity", "A lower equilibrium price and equilibrium quantity", "A lower equilibrium price and higher equilibrium quantity"], "hint": "Demand shifts LEFT along the unchanged supply curve — the new crossing point is lower AND further left.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — A lower equilibrium price and equilibrium quantity</strong></p>\n<ul>\n<li>A leftward demand shift moves the equilibrium down the supply curve: both price and quantity fall.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:646a21ce', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q23", "question": "Which of the following is predicted by the market forces of supply and demand?", "options": ["Equilibrium can only be achieved with government intervention", "Excess supply will occur if the price is below equilibrium", "If quantity demanded equals quantity supplied there is disequilibrium", "When there is excess demand the price will rise"], "hint": "Three options say the opposite of the theory. What do market forces do when buyers are competing for too few goods?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — When there is excess demand the price will rise</strong></p>\n<ul>\n<li>Excess demand bids the price up until equilibrium is restored — no government needed (A), below-equilibrium prices cause excess DEMAND (B), and Qd = Qs IS equilibrium (C).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:72469ef9', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q24", "question": "Goods A and B are substitutes. The supply of good A increases. What will happen in the market for good B?", "options": ["Demand will decrease", "Demand will increase", "Nothing", "The supply curve will shift to the right"], "hint": "Chain it: supply of A rises → price of A FALLS → A is now the cheaper substitute → what happens to demand for B?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Demand will decrease</strong></p>\n<ul>\n<li>More supply of A lowers A''s price. Buyers switch from B to the now-cheaper substitute A, so demand for B shifts left.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response was Option A. The incorrect responses were spread across the three distractors and indicated a relatively common misunderstanding of the interrelationships between markets and their products.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:422b3498', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q25", "question": "Which of the following is most likely to cause an increase in the price of oil?", "options": ["A decrease in the demand for oil", "A decrease in the oil industry''s labour costs", "A fall in the price of coal", "Reduced competition between oil producers"], "hint": "Three options push oil prices DOWN (less demand, lower costs, cheaper substitute). What happens to prices when producers stop competing with each other?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: D — Reduced competition between oil producers</strong></p>\n<ul>\n<li>Less competition (think OPEC restricting output) gives producers more control over price — prices rise.</li>\n<li>A, B and C all push the price of oil down.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A very high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:7e76158d', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q28", "question": "Which of the following would shift the supply curve for a good to the right?", "options": ["A fall in the firm''s costs of production", "A positive change in consumer tastes", "A successful advertising campaign", "A tax on the good"], "hint": "Two options are demand-side factors and one shifts supply LEFT. What makes supplying MORE profitable at every price?", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — A fall in the firm''s costs of production</strong></p>\n<ul>\n<li>Lower costs make each unit more profitable, so more is supplied at every price — supply shifts right.</li>\n<li>B and C shift DEMAND; a tax (D) raises costs and shifts supply LEFT.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:6d1aed06', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q29", "question": "If there is an increase in demand, how will this affect the equilibrium price and quantity when a supply curve is unitary price elastic?", "options": ["The equilibrium price and equilibrium quantity will both increase", "The equilibrium price will increase but equilibrium quantity will not change", "The equilibrium quantity will increase but equilibrium price will not change", "There will be no change because the market is already in equilibrium"], "hint": "Elasticity changes the EXTENT, never the direction. Demand shifts right along an upward-sloping (unitary) supply curve — both price and quantity move up.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — The equilibrium price and equilibrium quantity will both increase</strong></p>\n<ul>\n<li>A demand increase raises both price and quantity along any normal upward-sloping supply curve. Unitary elasticity only determines how the change is shared between them.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:93778293', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q30", "question": "The table provides information about the market for a good. The current price is £10. Which of the following statements is correct?", "options": ["Only a government price control can bring about equilibrium", "The current price is above the market equilibrium price", "There is excess demand of 200 units per week", "There is excess supply of 200 units per week"], "caseStudy": "<table style=\"width:100%;max-width:460px;margin:10px auto;border-collapse:collapse;text-align:center;\">\n<tr style=\"border-bottom:1px solid var(--border);\"><th style=\"padding:6px;\">Price (£)</th><th style=\"padding:6px;\">Quantity demanded (per week)</th><th style=\"padding:6px;\">Quantity supplied (per week)</th></tr>\n<tr><td style=\"padding:6px;\">5</td><td>600</td><td>150</td></tr>\n<tr><td style=\"padding:6px;\">10</td><td>500</td><td>300</td></tr>\n<tr><td style=\"padding:6px;\">15</td><td>400</td><td>400</td></tr>\n<tr><td style=\"padding:6px;\">20</td><td>300</td><td>350</td></tr>\n</table>", "hint": "At £10: quantity demanded 500, quantity supplied 300. Which is bigger, and by how much? (Equilibrium is at £15, where both read 400.)", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2, Quantitative skills)</h5>\n<p><strong>Answer: C — There is excess demand of 200 units per week</strong></p>\n<ul>\n<li>At £10, quantity demanded (500) exceeds quantity supplied (300) by 200 — excess demand. The price is BELOW the £15 equilibrium (where Qd = Qs = 400), and market forces will correct it without any government control.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:750f8d98', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q33", "question": "Prices change to show where resources are needed. This process is called...", "options": ["efficiency", "rationing", "signalling", "transmission of preferences"], "hint": "Prices as a beacon telling producers ''more resources over HERE'' — that''s the definition of one specific role.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — signalling</strong></p>\n<ul>\n<li>Signalling is the role where changing prices show where resources are needed — rising prices attract resources, falling prices release them.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response is Option C. Incorrect responses ranged across the other three options and indicated a lack of understanding of the role of price in determining the distribution of resources.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:eee991ae', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q34", "question": "Which of the following is the best explanation of equilibrium price and quantity?", "options": ["Price is the interaction of demand and supply to set the quantity", "Price is unlikely to change given existing demand and supply conditions", "Quantity has the same percentage change as any price change", "Quantity is fixed in relation to changes in demand and supply movements"], "hint": "The essence of equilibrium: NO PRESSURE TO CHANGE while demand and supply stay as they are.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: B — Price is unlikely to change given existing demand and supply conditions</strong></p>\n<ul>\n<li>At equilibrium there is no pressure for price (or quantity) to change unless demand or supply shifts — that is what makes it an equilibrium.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>The correct response is Option B. Incorrect responses ranged across the other three options and indicated a misunderstanding of what is meant by equilibrium price and quantity.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:exam:ef94fb11', 'economics', 'economics:2-4-price', '2.4 Price', 'exam', 'mcq', 1, '{"num": "Q35", "question": "Which of the following is the best explanation of the difference between price and worth?", "options": ["Price is determined by the interaction of demand and supply whereas worth is how consumers indicate their choices", "Price is how resources are efficiently distributed whereas worth is the opportunity cost of using the resources", "Price is the cost of a product whereas worth is how that price is determined by the market", "Price is the sum of money needed to pay for a product whereas worth is how much someone values the product"], "hint": "Price = the money you pay. Worth = the value YOU place on it. Only one option says both halves cleanly.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — Price is the sum of money needed to pay for a product whereas worth is how much someone values the product</strong></p>\n<ul>\n<li>Price is objective (the money required); worth is subjective (personal value) — option D captures both correctly.</li>\n</ul>\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:2-4-price:mcq:214b4773', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "Equilibrium price is best defined as the price at which...", "options": ["Quantity demanded equals quantity supplied", "Price equals quantity", "Producers make maximum profit", "The government sets the market price"]}'::jsonb, '{"answer": 0, "explain": "Equilibrium: Qd = Qs, the market clears, and there is no pressure for price to change. It does NOT mean price and quantity are ''equal to each other''."}'::jsonb),
('economics:2-4-price:mcq:5f36c582', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "A market price is set ABOVE the equilibrium. What follows?", "options": ["Excess supply — unsold stock builds up and the price falls", "Excess demand — the price rises further", "The market stays there permanently", "Quantity demanded rises"]}'::jsonb, '{"answer": 0, "explain": "Above equilibrium, quantity supplied exceeds quantity demanded — a surplus. Firms cut the price (think ''sale'') until the market clears."}'::jsonb),
('economics:2-4-price:mcq:1ec5d40e', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "A market price is set BELOW the equilibrium. What follows?", "options": ["Excess demand — stock runs out and the price is bid upwards", "Excess supply — the price falls", "Nothing changes", "Supply shifts left"]}'::jsonb, '{"answer": 0, "explain": "Below equilibrium, quantity demanded exceeds quantity supplied — a shortage. The price rises, rationing the scarce goods until equilibrium returns."}'::jsonb),
('economics:2-4-price:mcq:869e6058', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "Incomes rise sharply. In the market for restaurant meals (a normal good), the equilibrium...", "options": ["Price rises and quantity rises", "Price falls and quantity falls", "Price rises and quantity falls", "Price falls and quantity rises"]}'::jsonb, '{"answer": 0, "explain": "Higher incomes shift demand right along an unchanged supply curve — the new crossing point is higher and further right: both price and quantity rise."}'::jsonb),
('economics:2-4-price:mcq:d80e1cda', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "New technology halves the cost of making solar panels. The equilibrium in the solar panel market shows...", "options": ["A lower price and a higher quantity", "A higher price and a lower quantity", "A higher price and quantity", "No change"]}'::jsonb, '{"answer": 0, "explain": "Cheaper production shifts SUPPLY right: the price falls and the quantity bought and sold rises — the classic supply-shift outcome."}'::jsonb),
('economics:2-4-price:mcq:fd84f270', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "The price of strawberries rises after a poor harvest, so only those willing and able to pay the higher price buy them. This is price acting as...", "options": ["A rationing device", "A signal to consumers to buy more", "A transmission of producer preferences", "An equilibrium"]}'::jsonb, '{"answer": 0, "explain": "Rationing: the higher price reduces demand for the scarce good so the limited amount goes to those who value it most."}'::jsonb),
('economics:2-4-price:mcq:a2ab5b29', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "Farmers see the price of oat milk rising and switch fields from wheat to oats. Which role of price is this?", "options": ["Signalling", "Rationing", "Reflection of worth", "Bartering"]}'::jsonb, '{"answer": 0, "explain": "The rising price SIGNALS where resources are needed, pulling land, labour and capital into oat production."}'::jsonb),
('economics:2-4-price:mcq:8c88b02d', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "Both the supply of AND demand for a product increase at the same time. Which outcome is certain?", "options": ["The equilibrium quantity rises", "The equilibrium price rises", "The equilibrium price falls", "Both price and quantity fall"]}'::jsonb, '{"answer": 0, "explain": "Both shifts push quantity up, so quantity definitely rises. The price effect depends on which shift is bigger — supply right pushes it down, demand right pushes it up."}'::jsonb),
('economics:2-4-price:mcq:9dd14ce6', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "A chart shows the ANNUAL PERCENTAGE CHANGE in house prices falling from 14% to 8%. House prices are...", "options": ["Still rising, but at a slower rate", "Falling by 6%", "Falling by 8%", "Unchanged"]}'::jsonb, '{"answer": 0, "explain": "The chart plots the rate of change. Any value above zero means prices are still RISING — 8% growth is slower growth, not a fall. A real exam trap."}'::jsonb),
('economics:2-4-price:mcq:8426be21', 'economics', 'economics:2-4-price', '2.4 Price', 'mcq', 'mcq', 1, '{"question": "Supply shifts right in a market where demand is price INELASTIC. Compared with elastic demand, the result is...", "options": ["A bigger fall in price and a smaller rise in quantity", "A smaller fall in price and a bigger rise in quantity", "A rise in price", "No change in price"]}'::jsonb, '{"answer": 0, "explain": "Elasticity changes the EXTENT, not the direction: against inelastic demand the price does most of the adjusting — a large fall — while quantity barely moves."}'::jsonb),
('economics:2-4-price:tf:04afc469', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "At equilibrium, the price and the quantity are equal to each other."}'::jsonb, '{"answer": false, "explain": "Equilibrium means quantity DEMANDED equals quantity SUPPLIED — not that price equals quantity. Real candidates lost marks for exactly this confusion."}'::jsonb),
('economics:2-4-price:tf:cd3aa330', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "Shops usually hold ''cut price'' sales because the original price was above the equilibrium price."}'::jsonb, '{"answer": true, "explain": "Above equilibrium there''s excess supply — unsold stock. The sale cuts the price towards equilibrium to clear it. A real exam MCQ."}'::jsonb),
('economics:2-4-price:tf:94b55335', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "A shortage in a free market is permanent."}'::jsonb, '{"answer": false, "explain": "Shortages are self-correcting: excess demand bids the price up, which reduces quantity demanded and raises quantity supplied until the market clears."}'::jsonb),
('economics:2-4-price:tf:e2606fe8', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "A fall in demand leads to a lower equilibrium price AND a lower equilibrium quantity."}'::jsonb, '{"answer": true, "explain": "Demand shifts left along the unchanged supply curve — the new equilibrium is lower and further left on both measures."}'::jsonb),
('economics:2-4-price:tf:e730c643', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "If the annual percentage change in house prices falls from 14% to 8%, house prices have fallen."}'::jsonb, '{"answer": false, "explain": "Prices are still RISING — by 8% a year instead of 14%. The rate of increase fell, not the prices. Most real candidates got this wrong."}'::jsonb),
('economics:2-4-price:tf:7c6f1089', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "Elasticity changes the direction in which equilibrium price moves after a shift."}'::jsonb, '{"answer": false, "explain": "Elasticity only changes the EXTENT of the movement. Direction comes from which curve shifts and which way."}'::jsonb),
('economics:2-4-price:tf:8caaffe8', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "When there is excess demand, the market forces of supply and demand predict the price will rise."}'::jsonb, '{"answer": true, "explain": "Excess demand means buyers are competing for too few goods — the price is bid upwards until equilibrium is restored. A real exam MCQ."}'::jsonb),
('economics:2-4-price:tf:7fd20a66', 'economics', 'economics:2-4-price', '2.4 Price', 'tf', 'tf', 1, '{"question": "Price and worth are the same thing."}'::jsonb, '{"answer": false, "explain": "Price is the money needed to buy a product (same for everyone); worth is how much a PERSON values it — subjective and different for each buyer."}'::jsonb),
('economics:2-4-price:learn:750f8d98', 'economics', 'economics:2-4-price', '2.4 Price', 'learn', 'mcq', 1, '{"readingTitle": "Price as a reflection of worth — and the roles of price", "reading": "<p><strong>Price reflects the value or worth that people are willing to put on a good or service</strong> — which depends on the satisfaction (utility) they expect from it.</p>\n<h4>Price vs worth — a classic 2-marker</h4>\n<ul>\n<li><strong>Price</strong> — the sum of money that has to be paid to buy the product, determined by supply and demand. The same for everyone.</li>\n<li><strong>Worth</strong> — how much a PERSON values the product. It is <em>subjective</em> and varies from person to person (sentimental value!). Sophia''s charity-shop dress cost little but was worth a lot to her.</li>\n</ul>\n<h4>The roles of price in an economy — learn all five</h4>\n<ul>\n<li><strong>Signalling</strong> — prices change to show WHERE resources are needed. Rising organic vegetable prices signal farmers to grow more.</li>\n<li><strong>Rationing</strong> — when a resource is scarce its price rises, so only those willing and able to pay buy it, reducing demand and preserving the scarce resource.</li>\n<li><strong>Transmission of preferences</strong> — through their buying choices, consumers send information to producers about their changing needs and wants.</li>\n<li><strong>Reflection of worth</strong> — the price indicates to a consumer the benefit they might receive.</li>\n<li><strong>Incentivising</strong> — price changes give producers an incentive to act (higher prices → produce more).</li>\n</ul>\n<h4>Why this creates an efficient distribution of resources</h4>\n<ul>\n<li>If demand for a product rises, it must be delivering more utility. Its price rises, signalling producers to move resources INTO making it — and away from things people want less. No planner needed: <strong>consumer sovereignty</strong> means consumers steer production through what they buy.</li>\n</ul>", "question": "Prices change to show where resources are needed. This process is called...", "options": ["Signalling", "Rationing", "Transmission of preferences", "Efficiency"]}'::jsonb, '{"answer": 0, "explain": "Signalling is the ''follow the price'' role — rising prices pull resources in, falling prices push them away. This exact MCQ is on the real paper."}'::jsonb),
('economics:2-4-price:learn:b82ad49f', 'economics', 'economics:2-4-price', '2.4 Price', 'learn', 'mcq', 1, '{"readingTitle": "Equilibrium price and quantity", "reading": "<p><strong>Equilibrium price</strong> is the price at which <strong>quantity demanded exactly equals quantity supplied</strong>. The market <strong>clears</strong> — everything produced is sold, all buyers get what they want at that price, and there is <strong>no pressure for price or quantity to change</strong>.</p>\n<h4>Why markets move towards equilibrium — the self-correction</h4>\n<ul>\n<li><strong>Price ABOVE equilibrium → excess supply (surplus)</strong>: quantity supplied exceeds quantity demanded, so unsold stock builds up. Firms hold a ''cut price'' SALE to clear it — the price falls back towards equilibrium. (Real MCQ: shops usually hold sales because the original price was ABOVE equilibrium.)</li>\n<li><strong>Price BELOW equilibrium → excess demand (shortage)</strong>: quantity demanded exceeds quantity supplied, stock runs out. Suppliers raise prices, rationing the scarce goods — the price rises back towards equilibrium.</li>\n</ul>\n<h4>The role of the market</h4>\n<ul>\n<li>The market <strong>brings buyers and sellers together</strong> and is assumed always to move towards the equilibrium — this PROCESS is the answer to \"explain the role of the market in determining equilibrium\", not just the definition.</li>\n<li>Changes in supply or demand cause prices to establish a <strong>new</strong> equilibrium point.</li>\n</ul>\n<h4>Drawing the equilibrium diagram (a real 2-marker)</h4>\n<ul>\n<li>Downward-sloping D and upward-sloping S, BOTH labelled.</li>\n<li><strong>Mark the equilibrium</strong> where they cross — dotted lines to price p and quantity q. A correct diagram with no equilibrium indicated is only 1 mark; confusing the curves or leaving them unlabelled is 0.</li>\n</ul>\n<p><strong>Exam nuance:</strong> the equilibrium sets the <em>general level</em> of prices in a market — it is not a mandated price, which is why different brands can charge slightly different amounts.</p>", "question": "A competitive market is in equilibrium. Which statement is true?", "options": ["Quantity demanded equals quantity supplied", "Quantity supplied exceeds quantity demanded", "Consumers are unwilling to buy all the units produced", "Producers are leaving the industry"]}'::jsonb, '{"answer": 0, "explain": "Equilibrium = Qd = Qs, the market clears. This is a real exam MCQ — and note it does NOT mean ''price and quantity are equal to each other''!"}'::jsonb),
('economics:2-4-price:learn:29dab84e', 'economics', 'economics:2-4-price', '2.4 Price', 'learn', 'mcq', 1, '{"readingTitle": "Market forces — the four-part chain", "reading": "<p><strong>Market forces are demand and supply.</strong> Every shift question comes down to a 4-part chain: which curve shifts → which way → what happens to equilibrium price → what happens to equilibrium quantity.</p>\n<h4>The four outcomes — learn them cold</h4>\n<ul>\n<li><strong>Demand shifts RIGHT</strong> (incomes rise, advertising...) → price RISES and quantity RISES.</li>\n<li><strong>Demand shifts LEFT</strong> → price FALLS and quantity FALLS.</li>\n<li><strong>Supply shifts RIGHT</strong> (lower costs, more producers...) → price FALLS and quantity RISES.</li>\n<li><strong>Supply shifts LEFT</strong> (bad weather, higher costs...) → price RISES and quantity FALLS.</li>\n</ul>\n<h4>Combined shifts — the oil market example</h4>\n<ul>\n<li>Real papers love giving BOTH forces at once: oil production rose (S right → price down) while demand from developing countries grew (D right → price up). Quantity definitely rises; the final price depends on which shift is bigger. This matched petrol falling from 138.9p (2013) to 103.9p (2016), then rising to 117.9p (2017).</li>\n</ul>\n<h4>Then analyse the impact — the video-notes rule</h4>\n<ul>\n<li>For <strong>producers</strong>: build the argument around <strong>profits</strong>.</li>\n<li>For <strong>consumers</strong>: build it around <strong>quality of life</strong> (cheaper prices leave money for other things).</li>\n<li><strong>Watch the trick</strong>: if the \"consumers\" are actually other businesses buying inputs, analyse THEIR profits instead.</li>\n</ul>", "question": "Bad weather ruins the wheat crop. Using the 4-part chain, what happens in the wheat market?", "options": ["Supply shifts left → price rises and quantity falls", "Supply shifts right → price falls", "Demand shifts left → price falls", "Demand shifts right → price rises"]}'::jsonb, '{"answer": 0, "explain": "Weather is a supply-side factor: less wheat at every price, so S shifts left, price up, quantity down. ''Bad weather → higher wheat price'' is a real MCQ."}'::jsonb),
('economics:2-4-price:learn:e7039376', 'economics', 'economics:2-4-price', '2.4 Price', 'learn', 'mcq', 1, '{"readingTitle": "Elasticity and the EXTENT of the change", "reading": "<p>Elasticity never changes the <strong>direction</strong> equilibrium price and quantity move — only the <strong>extent</strong> of the movement. This one idea upgrades a Level 2 answer to Level 3.</p>\n<h4>The rule</h4>\n<ul>\n<li>Supply shifts right against <strong>price INELASTIC demand</strong> → LARGE fall in price, small rise in quantity.</li>\n<li>Supply shifts right against <strong>price ELASTIC demand</strong> → small fall in price, LARGE rise in quantity.</li>\n<li>The same logic applies to demand shifts against elastic/inelastic supply.</li>\n</ul>\n<h4>Real-market applications the spec expects</h4>\n<ul>\n<li><strong>Food (the Asian Hornet)</strong> — both demand and supply are price inelastic, so a supply shock raises price by far more than quantity falls.</li>\n<li><strong>Oil and petrol</strong> — inelastic supply means shifts cause rapid price changes in either direction; OPEC''s power partly depends on the PES of oil.</li>\n<li><strong>Housing</strong> — rising population and incomes push demand right against slow-to-respond supply: big price rises. Watch the data trap: a chart of the ANNUAL % CHANGE in house prices falling from 14% to 8% means prices are still RISING, just more slowly.</li>\n<li><strong>Sport and leisure / commodities</strong> — the same model applies to every market: identify the shift, apply the chain, scale it with elasticity.</li>\n</ul>\n<h4>Revenue on the diagram</h4>\n<ul>\n<li>Revenue = price × quantity = the RECTANGLE under the equilibrium point (P × Q). Selling 6 units at £3 shows as a shaded 6-by-£3 box = £18.</li>\n</ul>", "question": "Supply of a good shifts right. Demand for it is price inelastic. What happens?", "options": ["A large fall in price and a small rise in quantity", "A small fall in price and a large rise in quantity", "Price rises sharply", "Quantity falls"]}'::jsonb, '{"answer": 0, "explain": "Direction: S right → price down, quantity up. Extent: inelastic demand barely responds, so the price does most of the moving — a big fall."}'::jsonb),
('economics:2-4-price:misc:f4e39057', 'economics', 'economics:2-4-price', '2.4 Price', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Equilibrium price and quantity means the price and the quantity are equal.\"</p><p><strong>✅ The correct idea:</strong> Equilibrium is where quantity DEMANDED equals quantity SUPPLIED — the £15 row of a table where both columns read 400, not a row where price and quantity happen to match. The real examiner report said a significant number of candidates thought the term meant ''price and quantity are the same or are equal'' and scored 0. The full-mark sentence: <em>the price and quantity at which quantity demanded exactly matches quantity supplied, so the market clears and there is no pressure for price or quantity to change</em>. ''Where supply and demand cross'' alone is only 1 mark.</p>", "question": "A table shows: at £15, quantity demanded = 400 and quantity supplied = 400. What is £15?", "options": ["The equilibrium price — Qd equals Qs there", "A price where price equals quantity", "A price ceiling", "A disequilibrium price"]}'::jsonb, '{"answer": 0, "explain": "Equilibrium is the price where the two QUANTITIES match. That''s also the logic behind the real Q30 MCQ (at £10, Qd 500 > Qs 300 = excess demand of 200)."}'::jsonb),
('economics:2-4-price:misc:1a8084cf', 'economics', 'economics:2-4-price', '2.4 Price', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The house price chart fell after June — so house prices fell.\"</p><p><strong>✅ The correct idea:</strong> Check the Y-axis first! The chart plots the ANNUAL PERCENTAGE CHANGE in house prices. A fall from nearly 14% to just under 8% means prices were still RISING — by 8% a year instead of 14%. Prices only fall if the chart goes BELOW ZERO. The real mark scheme gave no marks at all for saying prices fell, and the examiner report said MORE candidates got this wrong than right. The 2-mark answer: prices continued to rise (1), but the rate of increase fell by about 6 percentage points (1).</p>", "question": "An annual-%-change chart shows +14% in June and +8% in July. Between June and July, prices...", "options": ["Rose by about 8%", "Fell by 6%", "Fell by 8%", "Stayed the same"]}'::jsonb, '{"answer": 0, "explain": "Above zero = still rising. The RATE of increase slowed from 14% to 8% — but 8% growth is still growth."}'::jsonb),
('economics:2-4-price:misc:5d65653a', 'economics', 'economics:2-4-price', '2.4 Price', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"There''s a surplus, so the market is broken and stuck.\"</p><p><strong>✅ The correct idea:</strong> In a free market, surpluses and shortages are SELF-CORRECTING — that is the whole point of the price mechanism. Excess supply → firms cut prices (the ''sale'') → quantity demanded rises and quantity supplied falls → equilibrium restored. Excess demand → prices are bid up → the scarce goods are rationed → equilibrium restored. A disequilibrium only persists if something holds the price away from equilibrium (like a government price control — festival tickets priced below the market-clearing level create chronic excess demand and resale markets). Explain the PROCESS, not just ''price falls'': the second mark on the real 2-marker was for explaining how the process continues until equilibrium.</p>", "question": "How does a free market respond to excess supply?", "options": ["The price falls until quantity demanded equals quantity supplied", "The government must intervene", "Producers permanently destroy stock", "Nothing — surpluses are permanent"]}'::jsonb, '{"answer": 0, "explain": "Self-correction through price: the surplus pushes the price down, which raises Qd and cuts Qs until the market clears. Explaining this process = both marks."}'::jsonb),
('economics:2-4-price:misc:ea20b7cd', 'economics', 'economics:2-4-price', '2.4 Price', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Explain the trend? I''ll describe every month of the data.\"</p><p><strong>✅ The correct idea:</strong> A trend is the GENERAL DIRECTION of the data over time — rewriting the numbers month by month scores NOTHING (''no mark for simply repeating the data''). The 2-mark formula: state the direction (petrol prices ROSE between January and July 2022) + either quantify it (by about 45p) or note the fluctuation (with a slight dip in April). Same for the petrol table: the price FELL then ROSE (1), and was still lower in 2017 (117.9p) than in 2013 (138.9p) (1). Compare start and end, name the direction, add one number.</p>", "question": "Petrol: 138.9p (2013), 130.9p, 109.9p, 103.9p, 117.9p (2017). The 2-mark trend answer is...", "options": ["The price fell then rose, ending lower than it started", "138.9, 130.9, 109.9, 103.9, 117.9", "The price changed a lot", "Petrol got more popular"]}'::jsonb, '{"answer": 0, "explain": "Direction + comparison of start and end. Listing the data back scores 0 — it ''fails to address explain''."}'::jsonb),
('economics:2-4-price:misc:1b0d08f3', 'economics', 'economics:2-4-price', '2.4 Price', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"''Market forces'' means competition between businesses.\"</p><p><strong>✅ The correct idea:</strong> Market forces are DEMAND and SUPPLY — full stop. On the real Tom''s baked potato 6-marker, candidates who did well elsewhere fell apart here because they wrote about competition tactics or how Tom could use prices, instead of starting from ''market forces consist of demand and supply'' and analysing how shifts in each affect his price and quantity sold. Good answers began with that definition, then applied it: demand for Tom''s food varies (demand shifts both ways), and the new cafés nearby are substitutes that shift his demand left → lower price and fewer sales.</p>", "question": "\"Analyse the effect of market forces on Tom''s business.\" Your first sentence should establish that market forces are...", "options": ["Demand and supply", "Competition and marketing", "Costs and revenues", "Imports and exports"]}'::jsonb, '{"answer": 0, "explain": "Define it, then apply it. The examiner report: candidates ''did not necessarily know about market forces'' and wrote about competition instead."}'::jsonb),
('economics:2-4-price:misc:67cf956e', 'economics', 'economics:2-4-price', '2.4 Price', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Oil is inelastic, so prices swing about.\"</p><p><strong>✅ The correct idea:</strong> Precision with elasticity language costs nothing and saves marks — OCR printed a ''need for precision'' note about this exact paper. Oil is not inelastic: <em>the demand for oil is price inelastic</em>. Petrol is not inelastic: <em>the demand for petrol is price inelastic</em>. Electric vehicles are not elastic: <em>the demand for petrol is expected to become more price elastic because of them</em>. And in Evaluate answers, a judgement that just summarises what you already said ''adds nothing new'' — take a side and support it with something extra (who it matters most for, when it stops mattering).</p>", "question": "Which sentence is precise enough for full credit?", "options": ["The demand for petrol is price inelastic", "Petrol is inelastic", "Oil is elastic", "Electric cars are elastic"]}'::jsonb, '{"answer": 0, "explain": "Name the concept in full: DEMAND for X is PRICE inelastic. The examiner report quoted all three sloppy versions as errors."}'::jsonb),
('economics:2-4-price:tips:515a224a', 'economics', 'economics:2-4-price', '2.4 Price', 'tips', 'mcq', 1, '{"readingTitle": "definitions — The 2-markers: equilibrium, roles of price, price vs worth", "reading": "<p>This paper''s 2-markers cluster around three ideas:</p>\n<ul>\n<li><strong>Equilibrium price and quantity</strong> — where quantity demanded exactly equals quantity supplied; the market clears; no pressure for price or quantity to change. (''Where S and D cross'' = only 1 mark.)</li>\n<li><strong>Roles of price</strong> — signalling, rationing, transmission of preferences, reflection of worth, incentives. Identify the role (1) + explain how it works (1). Read the exclusions: ''one OTHER role'' meant NO marks for signalling.</li>\n<li><strong>Price vs worth</strong> — price is the money paid (set by supply and demand, same for everyone); worth is how much a person values it (subjective, varies from person to person). Only a minority of real candidates got both halves.</li>\n</ul>\n<h4>How real answers scored</h4>\n<p>❌ <strong>0–1 mark:</strong> \"Worth is how much it cost to be produced\" — a real exemplar that scored 0 on the worth half.</p>\n<p>✅ <strong>2 marks:</strong> \"Price is how much a person has to pay for a good or service, whereas worth is how much someone values a product, not in monetary terms — and this can vary from person to person.\"</p>", "question": "\"Explain one OTHER role fulfilled by prices\" (signalling already given). Writing about signalling scores...", "options": ["0 marks — the question excluded it", "2 marks", "1 mark", "Half marks"]}'::jsonb, '{"answer": 0, "explain": "The mark scheme: ''No reward for any reference to the signalling role of prices.'' Read the exclusions before you write."}'::jsonb),
('economics:2-4-price:tips:d64dcbfa', 'economics', 'economics:2-4-price', '2.4 Price', 'tips', 'mcq', 1, '{"readingTitle": "diagrams — The signature 6-marker: ''Using a diagram, analyse market forces...''", "reading": "<p>Five of this paper''s nine 6-markers are the same shape: shift a curve (or two), read off the new equilibrium, chain the consequences.</p>\n<h4>The winning routine</h4>\n<ul>\n<li><strong>Identify the shift(s) from the extract</strong>: Asian Hornet → supply LEFT; rising incomes (Periff) → demand RIGHT; more airlines and flights (Northlisle) → supply RIGHT (and demand right too); oil: production up (S right) AND demand growth (D right).</li>\n<li><strong>Draw and label it</strong>: original and new curve, P→P1, Q→Q1. <strong>No correct diagram = capped at 4/6.</strong></li>\n<li><strong>Refer to the diagram explicitly</strong> in your writing — \"as shown in the diagram, the price rises from P to P1\". Candidates who drew a correct diagram but never mentioned it lost the link marks.</li>\n<li><strong>Separate price and quantity</strong> into two distinct strands of analysis — the examiner report praised exactly this.</li>\n<li><strong>Scale with elasticity</strong>: food is price inelastic both ways, so the Hornet''s supply shock moves price much more than quantity.</li>\n</ul>\n<h4>The trap</h4>\n<p>\"Market forces\" (plural) means consider BOTH demand and supply — candidates who covered only one were marked down for not reading the question.</p>", "question": "You write a perfect market-forces analysis but draw no diagram. Your maximum is...", "options": ["4 out of 6", "6 out of 6", "5 out of 6", "2 out of 6"]}'::jsonb, '{"answer": 0, "explain": "Every ''Using a diagram'' mark scheme on this paper: maximum 4 marks if no correct diagram. The diagram carries a knowledge mark and an analysis mark."}'::jsonb),
('economics:2-4-price:tips:69708fdc', 'economics', 'economics:2-4-price', '2.4 Price', 'tips', 'mcq', 1, '{"readingTitle": "data — Data questions: trends, tables and the %-change trap", "reading": "<p>Three data 2-markers appeared on this paper, and the mark schemes share one message: <strong>no marks for rewriting the data</strong>.</p>\n<h4>The formula</h4>\n<ul>\n<li><strong>State the direction</strong>: rose / fell / fell then rose.</li>\n<li><strong>Add one supporting number or feature</strong>: \"by about 45p\", \"with a slight fall in April\", \"still lower in 2017 (117.9p) than 2013 (138.9p)\".</li>\n</ul>\n<h4>The annual-%-change trap</h4>\n<ul>\n<li>The house-price chart plots the yearly percentage CHANGE. Falling from 14% to 8% means prices STILL ROSE — just more slowly. Saying prices fell = 0 marks. The AfL note: a chart like this can only show falling prices if it plots a value BELOW ZERO.</li>\n</ul>\n<h4>Table reading (real MCQ)</h4>\n<ul>\n<li>Current price £10: quantity demanded 500, quantity supplied 300 → excess DEMAND of 200 per week, and the price is BELOW equilibrium (£15, where both are 400).</li>\n</ul>", "question": "The 2-mark answer for \"explain the trend in petrol prices, Jan–Jul 2022\" is...", "options": ["Prices rose, by about 45p (with a small dip in April)", "A list of each month''s price", "Prices were volatile", "Prices fell because of OPEC"]}'::jsonb, '{"answer": 0, "explain": "Direction + quantification or fluctuation. The real mark scheme''s model answers are exactly these two sentences."}'::jsonb),
('economics:2-4-price:tips:64003aeb', 'economics', 'economics:2-4-price', '2.4 Price', 'tips', 'mcq', 1, '{"readingTitle": "sixmarker — Evaluate 6-markers: judgements must add something new", "reading": "<p>The examiner''s biggest complaint on this paper''s Evaluate questions: <strong>\"judgements were often concluding statements or summaries of previous issues within the response and so added nothing new\".</strong></p>\n<h4>How real answers scored</h4>\n<p>❌ <strong>Level 1:</strong> generic evaluation bolted on — \"however, this depends on many factors\".</p>\n<p>⚠️ <strong>Level 2:</strong> both sides covered, then \"Overall, PED is quite important for consumers\" — a summary, not a judgement.</p>\n<p>✅ <strong>Level 3:</strong> a judgement that adds a NEW discriminating idea: \"Overall, PED matters most for drivers who must commute and can''t cut back — but as electric vehicles spread and petrol demand becomes more price elastic, its importance will fall.\" (Who it matters for, and when it stops mattering.)</p>\n<h4>Also remember</h4>\n<ul>\n<li>''Evaluate the importance of'' means judge the IMPORTANCE — not just list effects.</li>\n<li>Different Evaluate questions demand different kinds of evaluation (''the importance'', ''the costs'', ''the extent to which'') — answer the one in front of you.</li>\n<li>Precision: <em>the demand for petrol is price inelastic</em>, never ''petrol is inelastic''.</li>\n</ul>", "question": "The examiner''s complaint about most Evaluate judgements was that they...", "options": ["Summarised earlier points and added nothing new", "Were too long", "Used too many diagrams", "Took too strong a side"]}'::jsonb, '{"answer": 0, "explain": "A Level 3 judgement discriminates — who it matters most for, under what conditions it changes — rather than repeating the answer in one sentence."}'::jsonb),
