('economics:2-4-price:match:9595c76b', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Equilibrium price”?", "options": ["The price at which quantity demanded exactly equals quantity supplied", "The quantity bought and sold when the market clears", "Everything produced is sold — nothing is left to buy or sell", "Price above equilibrium: quantity supplied exceeds quantity demanded, so the price falls"]}'::jsonb, '{"answer": 0, "explain": "“Equilibrium price” means: The price at which quantity demanded exactly equals quantity supplied"}'::jsonb),
('economics:2-4-price:match:1b0393ff', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Equilibrium quantity”?", "options": ["The quantity bought and sold when the market clears", "Everything produced is sold — nothing is left to buy or sell", "Price above equilibrium: quantity supplied exceeds quantity demanded, so the price falls", "Price below equilibrium: quantity demanded exceeds quantity supplied, so the price rises"]}'::jsonb, '{"answer": 0, "explain": "“Equilibrium quantity” means: The quantity bought and sold when the market clears"}'::jsonb),
('economics:2-4-price:match:0eb7a9a1', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market clearing”?", "options": ["Price above equilibrium: quantity supplied exceeds quantity demanded, so the price falls", "Price below equilibrium: quantity demanded exceeds quantity supplied, so the price rises", "Everything produced is sold — nothing is left to buy or sell", "Demand and supply — the forces that determine price and quantity in a market"]}'::jsonb, '{"answer": 2, "explain": "“Market clearing” means: Everything produced is sold — nothing is left to buy or sell"}'::jsonb),
('economics:2-4-price:match:965ff80d', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Excess supply (surplus)”?", "options": ["Price above equilibrium: quantity supplied exceeds quantity demanded, so the price falls", "Price below equilibrium: quantity demanded exceeds quantity supplied, so the price rises", "Demand and supply — the forces that determine price and quantity in a market", "Prices changing to show producers where resources are needed"]}'::jsonb, '{"answer": 0, "explain": "“Excess supply (surplus)” means: Price above equilibrium: quantity supplied exceeds quantity demanded, so the price falls"}'::jsonb),
('economics:2-4-price:match:e55f8ee8', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Excess demand (shortage)”?", "options": ["Demand and supply — the forces that determine price and quantity in a market", "Prices changing to show producers where resources are needed", "A rising price reducing demand for a scarce resource so it goes to those willing and able to pay", "Price below equilibrium: quantity demanded exceeds quantity supplied, so the price rises"]}'::jsonb, '{"answer": 3, "explain": "“Excess demand (shortage)” means: Price below equilibrium: quantity demanded exceeds quantity supplied, so the price rises"}'::jsonb),
('economics:2-4-price:match:79771b2e', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market forces”?", "options": ["Prices changing to show producers where resources are needed", "A rising price reducing demand for a scarce resource so it goes to those willing and able to pay", "Consumers sending information to producers about their wants through what they buy", "Demand and supply — the forces that determine price and quantity in a market"]}'::jsonb, '{"answer": 3, "explain": "“Market forces” means: Demand and supply — the forces that determine price and quantity in a market"}'::jsonb),
('economics:2-4-price:match:7df42514', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Signalling”?", "options": ["A rising price reducing demand for a scarce resource so it goes to those willing and able to pay", "Prices changing to show producers where resources are needed", "Consumers sending information to producers about their wants through what they buy", "The sum of money needed to pay for a product, determined by supply and demand"]}'::jsonb, '{"answer": 1, "explain": "“Signalling” means: Prices changing to show producers where resources are needed"}'::jsonb),
('economics:2-4-price:match:87c204bc', 'economics', 'economics:2-4-price', '2.4 Price', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Rationing”?", "options": ["A rising price reducing demand for a scarce resource so it goes to those willing and able to pay", "Consumers sending information to producers about their wants through what they buy", "The sum of money needed to pay for a product, determined by supply and demand", "How much someone personally values a product — subjective and different for each person"]}'::jsonb, '{"answer": 0, "explain": "“Rationing” means: A rising price reducing demand for a scarce resource so it goes to those willing and able to pay"}'::jsonb)
